import React, { useMemo, useEffect, useRef, useState } from "react";
import Grid from "./components/Grid/Grid";
import { getImage } from "./utils/getImage";
import Lightbox from "./components/Lightbox/Lightbox";
import Header from "./components/Header/Header";
import { Helmet } from 'react-helmet-async';
import { HelmetProvider } from 'react-helmet-async';
import data from "./data/portfolio.json";
const rawItems = data.items;
const { temas, tags, usos } = data.dicts;
const items = rawItems.map((item) => {
  const temasLabels = item.meta.temas.map((i) => temas[i]);
  const tagsLabels = item.meta.tags.map((i) => tags[i]);
  const usosLabels = item.meta.usos.map((i) => usos[i]);

  const allFilters = [...temasLabels, ...tagsLabels, ...usosLabels];
  const allFiltersLower = allFilters.map(f => f.toLowerCase());

  // Corregir categoría: mapear "otros" según el prefijo del ID
  let categoria = item.categoria;
  if (categoria === "otros") {
    if (item.id.startsWith("ilu-")) {
      categoria = "ilustracion";
    } else if (item.id.startsWith("dis-")) {
      categoria = "diseno";
    }
  }

  return {
    ...item,
    categoria, // ← Sobreescribimos con la categoría corregida
    temasLabels,
    tagsLabels,
    usosLabels,
    allFilters,
    allFiltersLower,
  };
});

/* =========================
   1) UTILIDADES
========================= */
const gridCardBase = {
  all: "unset",
  display: "block",
  cursor: "pointer",
  width: "100%",
  borderRadius: "12px",
  overflow: "hidden",
  background: "#fff",
  transition: "all 0.25s ease",
};

/* =========================
   2) COMPONENTE
========================= */
import usePortfolio from "./hooks/usePortfolio";
export default function Portfolio() {

const [lightboxOpen, setLightboxOpen] = useState(false);
const [searchOpen, setSearchOpen] = useState(false);
const [filtersOpen, setFiltersOpen] = useState(false);
const [openPanel, setOpenPanel] = useState(null);
const [hoveredPanel, setHoveredPanel] = useState(null);
const [hovered, setHovered] = useState(null);
const [zoom, setZoom] = useState(false);
const [gridTransition, setGridTransition] = useState(true);
const gridScrollRef = useRef(0);

  const {
  query,
  setQuery,
  category,
  setCategory,
  filters,
  setFilters,
  filtered,
  paginated,
  page,
  setPage,
  selected,
  setSelected,
} = usePortfolio();

  const pageSelected = paginated.find((item) => item.id === selected?.id) || null;

  useEffect(() => {
    if (!selected) return;
    const index = filtered.findIndex((i) => i.id === selected.id);
    const next = filtered[index + 1];
    if (next) {
      const img = new Image();
      img.src = getImage(next, "full");
    }

    const prev = filtered[index - 1];
    if (prev) {
      const imgPrev = new Image();
      imgPrev.src = getImage(prev, "full");
    }
  }, [selected, filtered]);
  useEffect(() => {
  setGridTransition(false);
  setPage(1);
  const t = setTimeout(() => setGridTransition(true), 150);
  return () => clearTimeout(t);
}, [filtered]);
  useEffect(() => {
  const handleKey = (e) => {
    // No activar atajos si el usuario está escribiendo en un input
    const tag = document.activeElement?.tagName?.toLowerCase();
    if (tag === "input" || tag === "textarea" || tag === "select") return;

    // === LIGHTBOX ABIERTO ===
    if (lightboxOpen) {
      if (e.key === "Escape") {
  e.preventDefault();
  setZoom(false);
  setTimeout(() => {
    setLightboxOpen(false);
    setSelected(null);
    // Restaurar scroll
    setTimeout(() => {
      window.scrollTo({ top: gridScrollRef.current, behavior: "instant" });
    }, 50);
  }, 200);
  return;
}
      if (e.key === "ArrowRight") {
        e.preventDefault();
        //goNext();
        return;
      }
      if (e.key === "ArrowLeft") {
        e.preventDefault();
        //goPrev();
        return;
      }
      // Zoom con tecla + / =
      if (e.key === "+" || e.key === "=") {
        e.preventDefault();
        setZoom(true);
        return;
      }
      if (e.key === "-") {
        e.preventDefault();
        setZoom(false);
        return;
      }
      return; // Si el lightbox está abierto, ignorar el resto
    }

    // === LIGHTBOX CERRADO: atajos globales ===

    if (e.key === "/" || (e.ctrlKey && e.key === "k")) {
      // Abrir búsqueda
      e.preventDefault();
      setSearchOpen(true);
      return;
    }
    if (e.key === "Escape") {
      // Cerrar búsqueda, filtros o menú si están abiertos
      if (searchOpen) {
        setSearchOpen(false);
        return;
      }
      if (openPanel === "menu") {
        setOpenPanel(null);
        return;
      }
      // Limpiar selección
      setSelected(null);
      setQuery("");
      setCategory("todas");
      setFilters([]);
    }
  };

  window.addEventListener("keydown", handleKey);
  return () => window.removeEventListener("keydown", handleKey);
}, [lightboxOpen, searchOpen, filtersOpen, openPanel]);

  const isSingle = filtered.length <= 2;
  const leftText = useMemo(
    () => `
Me llamo Arturo Morales Pérez, soy laico marista de Champagnat, y formo parte de la Provincia Marista Mediterránea.

Además de mi tarea habitual (educador y catequista) a menudo suelo crear diseños e ilustraciones, o adaptarlos a formato digital, para lo propio de nuestras acciones pastorales, educativas, vocacionales, sociales y comunitarias.

Esta web/app tiene una finalidad sencilla: servir de repositorio de imágenes que he podido ir creando o vectorizando, relacionadas con esos fines. Se incluyen adaptaciones de dibujos o ilustraciones encontradas por la red o que han compartido conmigo. En esos casos, aparecerá "adaptada" en el título y, siempre que lo haya encontrado, citando el autor de la imagen o fragmento adaptado.

No es por tanto un estudio de diseño online ni una web de compras o marketing, ni siquiera una página personal como artista. Todo es abierto (licencia Creative Commons, ver Nota Legal), y descargable, esperando que sirva para inspirar o ayudar en vuestras tareas.

Encantado de veros por aquí.
`,
    []
  );

  useEffect(() => {
    if (selected) {
      window.history.replaceState(null, "", `#${selected.id}`);
    }
  }, [selected]);
  useEffect(() => {
  if (lightboxOpen && lightboxRef.current) {
    const first = lightboxRef.current.querySelector(
      'button, [href], [tabindex]:not([tabindex="-1"])'
    );
    first?.focus();
  }
}, [lightboxOpen]);
  useEffect(() => {
    const hash = window.location.hash.replace("#", "");
    if (hash) {
      const found = items.find((item) => item.id === hash);
      if (found) setSelected(found);
    }
  }, []);
  useEffect(() => {
  if (lightboxOpen) {
    gridScrollRef.current = window.scrollY;
    document.body.style.overflow = "hidden";
  } else {
    document.body.style.overflow = "auto";
  }
  return () => {
    document.body.style.overflow = "auto";
  };
}, [lightboxOpen]);
  return (
  <HelmetProvider>
    <div>
      <Helmet>
        <title>{selected ? selected.titulo : "Marist-Art"}</title>
        <link rel="manifest" href="/manifest.json" />
        <meta
          name="description"
          content="Repositorio de ilustraciones maristas gratuitas"
        />
        <meta property="og:title" content={selected?.titulo || "Marist-Art"} />
        <meta
          property="og:image"
          content={selected?.imagenes?.thumb || "/logo.png"}
        />
        <meta name="theme-color" content="#4f677d" />
        <meta name="viewport" content="width=device-width, initial-scale=1" />
      </Helmet>
      <div
        style={{
          fontFamily: "'Montserrat', sans-serif",
          minHeight: "100vh",
          background:
            "linear-gradient(135deg, rgba(120, 80, 200, 0.7), rgba(60, 120, 200, 0.7), rgba(120, 120, 120, 0.7))",
          color: "#111",
        }}
      >
        {/* HEADER */}
<Header
  query={query}
  setQuery={setQuery}
  category={category}
  setCategory={setCategory}
  filters={filters}
  setFilters={setFilters}
  filteredCount={filtered.length}
  //isMobile={isMobile}
  searchOpen={searchOpen}
  setSearchOpen={setSearchOpen}
  openPanel={openPanel}
  setOpenPanel={setOpenPanel}
  onLogoClick={() => {
    setQuery("");
    setCategory("todas");
    setFilters([]);
    setSelected(null);
  }}
  //onContactClick={handleContactClick}
/>

{/* FILTROS - También superpuesto sobre el grid */}
<Filters
  filters={filters}
  setFilters={setFilters}
  groups={groups}
/>
       {/* PAGINACIÓN SUPERIOR */}
{filtered.length > pageSize && (
  <div style={{
    textAlign: "center",
    padding: 0,
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    gap: "12px",
  }}>
    <button
      type="button"
      onClick={() => {
  setGridTransition(false);
  setTimeout(() => {
    setPage((p) => p - 1);
    setGridTransition(true);
  }, 150);
}}
      disabled={page === 1}
      style={{
        background: "rgba(255,255,255,0.2)",
        color: page === 1 ? "rgba(255,255,255,0.25)" : "#fff",
        border: "1px solid rgba(255,255,255,0.2)",
        borderRadius: "50%",
        width: "36px",
        height: "36px",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        cursor: page === 1 ? "default" : "pointer",
        fontSize: "16px",
        transition: "all 0.2s ease",
      }}
      aria-label="Página anterior"
    >
      ←
    </button>

    <span style={{
      color: "rgba(255,255,255,0.6)",
      fontSize: "13px",
      fontStyle: "italic",
    }}>
      {page} / {Math.ceil(filtered.length / pageSize)}
    </span>

    <button
      type="button"
      onClick={() => {
  setGridTransition(false);
  setTimeout(() => {
    setPage((p) => p + 1);
    setGridTransition(true);
  }, 150);
}}
      disabled={page * pageSize >= filtered.length}
      style={{
        background: "rgba(255,255,255,0.2)",
        color: page * pageSize >= filtered.length ? "rgba(255,255,255,0.25)" : "#fff",
        border: "1px solid rgba(255,255,255,0.2)",
        borderRadius: "50%",
        width: "36px",
        height: "36px",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        cursor: page * pageSize >= filtered.length ? "default" : "pointer",
        fontSize: "16px",
        transition: "all 0.2s ease",
      }}
      aria-label="Página siguiente"
    >
      →
    </button>
  </div>
)}
        {/* GRID */}
<div
  style={{
    padding: "12px 20px",
    opacity: gridTransition ? 1 : 0,
    transform: gridTransition ? "translateY(0)" : "translateY(8px)",
    transition: "opacity 0.2s ease, transform 0.2s ease",
    minHeight: filtered.length === 0 ? "200px" : "auto",
  }}
>
  {filtered.length === 0 && (
    <div
      style={{
        textAlign: "center",
        color: "white",
        fontSize: "16px",
        padding: "40px 0",
        fontStyle: "italic",
      }}
    >
      Sin resultados. Prueba a modificar búsqueda o filtros.
    </div>
  )}

  <Grid
  items={paginated}
  selectedId={pageSelected?.id}
  //onSelect={changeSelected}
  hoveredId={hovered}
  setHovered={setHovered}
  isSingle={isSingle}
/>
</div>
<Lightbox
  selected={selected}
  isOpen={lightboxOpen}
  onClose={() => {
    setZoom(false);
    setLightboxOpen(false);
    setSelected(null);
    setTimeout(() => {
      window.scrollTo({ top: gridScrollRef.current });
    }, 50);
  }}
  //onNext={goNext}
  //onPrev={goPrev}
  //isMobile={isMobile}
  zoom={zoom}
  setZoom={setZoom}
/>
       {/* PAGINACIÓN INFERIOR (idéntica) */}
{filtered.length > pageSize && (
  <div style={{
    textAlign: "center",
    padding: "8px 0 20px",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    gap: "12px",
  }}>
    <button
      type="button"
      onClick={() => {
  setGridTransition(false);
  setTimeout(() => {
    setPage((p) => p - 1);
    setGridTransition(true);
  }, 150);
}}
      disabled={page === 1}
      style={{
        background: "rgba(255,255,255,0.2)",
        color: page === 1 ? "rgba(255,255,255,0.25)" : "#fff",
        border: "1px solid rgba(255,255,255,0.2)",
        borderRadius: "50%",
        width: "36px",
        height: "36px",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        cursor: page === 1 ? "default" : "pointer",
        fontSize: "16px",
        transition: "all 0.2s ease",
      }}
      aria-label="Página anterior"
    >
      ←
    </button>

    <span style={{
      color: "rgba(255,255,255,0.6)",
      fontSize: "13px",
      fontStyle: "italic",
    }}>
      {page} / {Math.ceil(filtered.length / pageSize)}
    </span>

    <button
      type="button"
      onClick={() => {
  setGridTransition(false);
  setTimeout(() => {
    setPage((p) => p + 1);
    setGridTransition(true);
  }, 150);
}}
      disabled={page * pageSize >= filtered.length}
      style={{
        background: "rgba(255,255,255,0.2)",
        color: page * pageSize >= filtered.length ? "rgba(255,255,255,0.25)" : "#fff",
        border: "1px solid rgba(255,255,255,0.2)",
        borderRadius: "50%",
        width: "36px",
        height: "36px",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        cursor: page * pageSize >= filtered.length ? "default" : "pointer",
        fontSize: "16px",
        transition: "all 0.2s ease",
      }}
      aria-label="Página siguiente"
    >
      →
    </button>
  </div>
)}
        {/* INFOPANELS */}
        <div
          id="info-panels"
          style={{
            background: "rgb(79, 103, 125)",
            padding: "24px 20px 28px",
            marginTop: "20px",
            marginBottom: "0",
          }}
        >
          {/* los dos paneles */}
          <div
            style={{
              display: "flex",
              flexWrap: "wrap",
              gap: "30px",
              alignItems: "flex-start",
              justifyContent: "center",
              maxWidth: "1200px",
              margin: "0 auto",
            }}
          >
            {/* IZQUIERDA */}
            <div
              onClick={() => setOpenPanel(openPanel === "left" ? null : "left")}
              onMouseEnter={() => setHoveredPanel("left")}
              onMouseLeave={() => setHoveredPanel(null)}
              style={{
                flex: "1 1 360px",
                minWidth: "280px",
                background: "#fff",
                borderRadius: "18px",
                overflow: "hidden",
                cursor: "pointer",
                transition:
                  "transform 0.2s ease, box-shadow 0.2s ease, min-height 0.3s ease",
                height: openPanel === "left" ? "auto" : "110px",
                boxShadow:
                  hoveredPanel === "left"
                    ? "0 12px 28px rgba(0,0,0,0.18)"
                    : "0 6px 18px rgba(0,0,0,0.12)",
                transform:
                  hoveredPanel === "left" ? "scale(1.015)" : "scale(1)",
                display: "flex",
                flexDirection: "column",
              }}
            >
              <div
                style={{
                  padding: "16px 20px 6px",
                  fontFamily: "Montserrat, sans-serif",
                  fontStyle: "italic",
                  color: "#555",
                  fontSize: "20px",
                  lineHeight: 1.1,
                  flexShrink: 0,
                }}
              >
                Presentación y Nota Legal
              </div>
              <div
                style={{
                  padding: "0 20px 20px",
                  color: "#666",
                  fontSize: "14px",
                  lineHeight: 1.4,
                  overflow: "hidden",
                  display: "-webkit-box",
                  WebkitLineClamp: openPanel === "left" ? "unset" : 3,
                  WebkitBoxOrient: "vertical",
                  overflow: "hidden",
                  position: "relative",

                  whiteSpace: "pre-line",
                  textAlign: "justify",
                  textAlignLast: "left",
                }}
              >
                {openPanel === "left" ? (
                  <>
                    {leftText.split("\n\n").map((p, i) => (
                      <p key={i} style={{ margin: "0 0 12px" }}>
                        {p}
                      </p>
                    ))}
                    <div
                      style={{
                        display: "flex",
                        justifyContent: "center",
                        marginTop: "16px",
                      }}
                    >
                      <a
                        href="/data/notaslegales.pdf"
                        target="_blank"
                        rel="noopener noreferrer"
                        onClick={(e) => e.stopPropagation()}
                        style={{
                          padding: "8px 16px",
                          borderRadius: "6px",
                          border: "1px solid #ccc",
                          background: "#fff",
                          color: "#444",
                          fontSize: "12px",
                          fontStyle: "italic",
                          textDecoration: "none",
                          cursor: "pointer",
                        }}
                      >
                        Aviso Legal
                      </a>
                    </div>
                  </>
                ) : (
                  <div style={{ position: "relative" }}>
                    <span style={{ display: "block" }}>{leftText}</span>
                    {/* degradado SOLO cuando está cerrado */}
                    <div
                      style={{
                        position: "absolute",
                        bottom: 0,
                        left: 0,
                        right: 0,
                        height: "40px",
                        background:
                          "linear-gradient(to bottom, rgba(255,255,255,0), rgba(255,255,255,0.9), rgba(255,255,255,1))",
                        pointerEvents: "none",
                      }}
                    />
                  </div>
                )}
              </div>
            </div>
            {/* DERECHA */}
            <div
              onClick={() =>
                setOpenPanel(openPanel === "right" ? null : "right")
              }
              onMouseEnter={() => setHoveredPanel("right")}
              onMouseLeave={() => setHoveredPanel(null)}
              style={{
                flex: "1 1 360px",
                minWidth: "280px",
                background: "#fff",
                borderRadius: "18px",
                overflow: "hidden",
                cursor: "pointer",
                transition:
                  "transform 0.2s ease, box-shadow 0.2s ease, min-height 0.3s ease",
                height: openPanel === "right" ? "auto" : "110px",
                boxShadow:
                  hoveredPanel === "right"
                    ? "0 12px 28px rgba(0,0,0,0.18)"
                    : "0 6px 18px rgba(0,0,0,0.12)",
                transform:
                  hoveredPanel === "right" ? "scale(1.015)" : "scale(1)",
                display: "flex",
                flexDirection: "column",
              }}
            >
              <div
                style={{
                  padding: "16px 20px 6px",
                  fontFamily: "Montserrat, sans-serif",
                  fontStyle: "italic",
                  color: "#555",
                  fontSize: "20px",
                  lineHeight: 1.1,
                  flexShrink: 0,
                }}
              >
                Consulta y Contacto
              </div>
              <div
                style={{
                  padding: "0 20px 20px",
                  color: "#666",
                  fontSize: "14px",
                  lineHeight: 1.4,
                  overflow: "hidden",
                  position: "relative",
                }}
              >
                {openPanel === "right" ? (
                  <>
                    <div style={{ marginTop: "18px" }}>
                      Si tienes cualquier duda, consulta o aportación, puedes
                      hacerlo desde aquí. Tus datos sólo se usarán para este
                      fin.
                    </div>

                    {/* FORMULARIO */}
                    <div
                      style={{
                        opacity: openPanel === "right" ? 1 : 0,
                        maxHeight: openPanel === "right" ? "500px" : "0px",
                        overflow: "hidden",
                        transition: "opacity 0.25s ease, max-height 0.3s ease",
                        pointerEvents: openPanel === "right" ? "auto" : "none",
                        marginTop: openPanel === "right" ? "12px" : "0px",
                      }}
                    >
                      <form
                        onSubmit={async (e) => {
                          e.preventDefault();
                          e.stopPropagation();

                          setLoading(true);

                          const formData = new FormData(e.target);

                          const res = await fetch(
                            "https://formspree.io/f/mnjlgkyw",
                            {
                              method: "POST",
                              body: formData,
                              headers: { Accept: "application/json" },
                            }
                          );

                          if (res.ok) {
                            setSent(true);
                            e.target.reset();
                          }

                          setLoading(false);
                        }}
                        onClick={(e) => e.stopPropagation()}
                        style={{
                          display: "flex",
                          flexDirection: "column",
                          gap: "8px",
                          maxWidth: "300px",
                        }}
                      >
                        <input
                          type="email"
                          name="email"
                          placeholder="Tu email"
                          required
                          style={{
                            padding: "8px 10px",
                            borderRadius: "6px",
                            border: "1px solid #ccc",
                            fontSize: "13px",
                            fontFamily: "Montserrat, sans-serif",
                            outline: "none",
                          }}
                          onFocus={(e) =>
                            (e.target.style.border = "1px solid #0b1f4d")
                          }
                          onBlur={(e) =>
                            (e.target.style.border = "1px solid #ccc")
                          }
                        />
                        <textarea
                          name="message"
                          placeholder="Mensaje"
                          required
                          rows={4}
                          style={{
                            padding: "8px 10px",
                            borderRadius: "6px",
                            border: "1px solid #ccc",
                            fontSize: "13px",
                            fontFamily: "Montserrat, sans-serif",
                            outline: "none",
                            resize: "vertical",
                          }}
                          onFocus={(e) =>
                            (e.target.style.border = "1px solid #0b1f4d")
                          }
                          onBlur={(e) =>
                            (e.target.style.border = "1px solid #ccc")
                          }
                        />
                        <button
                          type="submit"
                          disabled={loading}
                          style={{
                            padding: "8px 12px",
                            borderRadius: "6px",
                            border: "1px solid #ccc",
                            background: "#fff",
                            fontSize: "13px",
                            fontFamily: "Montserrat, sans-serif",
                            cursor: "pointer",
                            transition: "all 0.2s ease",
                          }}
                          onMouseEnter={(e) => {
                            e.currentTarget.style.background = "#f0f0f0";
                          }}
                          onMouseLeave={(e) => {
                            e.currentTarget.style.background = "#fff";
                          }}
                        >
                          {loading ? "Enviando..." : "Enviar"}
                        </button>
                        {sent && (
                          <div
                            role="status"
                            aria-live="polite"
                            style={{
                              marginTop: "10px",
                              fontSize: "12px",
                              color: "#0b1f4d",
                              fontStyle: "italic",
                            }}
                          >
                            ✔ Mensaje enviado correctamente
                          </div>
                        )}
                      </form>
                    </div>
                  </>
                ) : (
                  <div style={{ position: "relative" }}>
                    <span style={{ display: "block" }}>
                      Si tienes cualquier duda, consulta o aportación, puedes
                      hacerlo desde aquí. Tus datos sólo se usarán para este
                      fin.
                    </span>

                    {/* degradado */}
                    <div
                      style={{
                        position: "absolute",
                        bottom: 0,
                        left: 0,
                        right: 0,
                        height: "40px",
                        background:
                          "linear-gradient(to bottom, rgba(255,255,255,0), rgba(255,255,255,1))",
                        pointerEvents: "none",
                      }}
                    />
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
      <div
        style={{
          background: "#fff",
          padding: "16px 24px",
          display: "flex",
          alignItems: "left",
          justifyContent: "space-between",
          marginTop: "0px",
          fontFamily: "'Montserrat', sans-serif",
        }}
      >
        <div style={{ flex: 1 }}></div>
        <div
          style={{
            flex: 1,
            textAlign: "left",
            color: "#777",
            fontSize: "12px",
          }}
        >
          © AMP 2026
        </div>
        <img
          src="/logo.png"
          alt="Marist-Art"
          style={{
            height: "40px",
            objectFit: "contain",
            cursor: "pointer",
            opacity: 0.9,
            transition: "opacity 0.2s ease",
          }}
          onMouseEnter={(e) => (e.currentTarget.style.opacity = 1)}
          onMouseLeave={(e) => (e.currentTarget.style.opacity = 0.9)}
          onClick={() => {
            setQuery("");
            setCategory("todas");
            setFilters([]);
          }}
        />
      </div>
    </div>
  </HelmetProvider>
);
